module RefModule (
    input wire d,
    input wire we,
    input wire clk,
    output reg q
);
    reg obf_stored_bit;

    always @(posedge clk) begin
        if (we) begin
            obf_stored_bit <= d;
        end
    end

    always @* begin
        q = obf_stored_bit;
    end
endmodule
